t.script:
(function () {
    const BAF_API = {
        search: '/b2b/part-search',
        addToCart: '/b2b/cart/add',
        upload: '/b2b/upload-parts-list',
    };

    function jsonrpc(url, params) {
        return fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                params: params || {},
                id: Math.floor(Math.random() * 1e9),
            }),
            credentials: 'same-origin',
        }).then(function (res) {
            if (!res.ok) throw new Error('HTTP ' + res.status);
            return res.json();
        }).then(function (body) {
            if (body.error) throw new Error(body.error.data ? body.error.data.message : body.error.message);
            return body.result;
        });
    }

    function escapeHtml(value) {
        return String(value == null ? '' : value)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#039;');
    }

    function normalizePartNumbers(input) {
        return String(input || '')
            .split(/[\n\r,;\t]/)
            .map(function (part) { return part.trim(); })
            .filter(Boolean);
    }

    document.addEventListener('DOMContentLoaded', function () {
        const tabs = document.querySelectorAll('.baf-tab');
        const panels = document.querySelectorAll('.baf-tab-panel');
        const statusBox = document.getElementById('bafStatus');
        const resultsBody = document.getElementById('resultsBody');
        const resultsEmpty = document.getElementById('resultsEmpty');
        const resultsTableWrap = document.getElementById('resultsTableWrap');
        const ambiguousBox = document.getElementById('bafAmbiguous');
        const notFoundBox = document.getElementById('bafNotFound');
        const addSelectedBtn = document.getElementById('addSelectedBtn');
        const selectAll = document.getElementById('selectAll');
        const cartInfo = document.getElementById('bafCartInfo');

        tabs.forEach(function (tab) {
            tab.addEventListener('click', function () {
                tabs.forEach(function (item) { item.classList.remove('is-active'); });
                panels.forEach(function (panel) { panel.classList.remove('is-active'); });
                tab.classList.add('is-active');
                document.getElementById(tab.dataset.tab).classList.add('is-active');
            });
        });

        document.getElementById('singleSearchBtn').addEventListener('click', function () {
            searchParts(normalizePartNumbers(document.getElementById('singlePart').value));
        });
        document.getElementById('singlePart').addEventListener('keydown', function (event) {
            if (event.key === 'Enter') {
                event.preventDefault();
                searchParts(normalizePartNumbers(document.getElementById('singlePart').value));
            }
        });
        document.getElementById('multiSearchBtn').addEventListener('click', function () {
            searchParts(normalizePartNumbers(document.getElementById('multiParts').value));
        });
        document.getElementById('uploadBtn').addEventListener('click', uploadPartsList);

        selectAll.addEventListener('change', function () {
            document.querySelectorAll('.baf-row-select').forEach(function (cb) { cb.checked = selectAll.checked; });
            updateSelectedButton();
        });
        addSelectedBtn.addEventListener('click', function () {
            const selected = getSelectedItems();
            if (selected.length) addItemsToCart(selected);
        });

        async function searchParts(partNumbers, brandChoices) {
            if (!partNumbers || !partNumbers.length) {
                setStatus('Bitte mindestens eine Teilenummer eingeben.');
                return;
            }
            setStatus('Teilenummern werden geprüft...');
            try {
                const result = await jsonrpc(BAF_API.search, {
                    part_numbers: partNumbers,
                    brand_choices: brandChoices || {},
                });
                renderResults(result);
            } catch (error) {
                console.error(error);
                setStatus('Die Suche konnte nicht ausgeführt werden. Bitte erneut versuchen.');
            }
        }

        async function resolveAmbiguous(choices) {
            const skus = Object.keys(choices);
            if (!skus.length) {
                setStatus('Bitte mindestens eine Marke auswählen.');
                return;
            }
            setStatus('Auswahl wird übernommen...');
            try {
                const result = await jsonrpc(BAF_API.search, {
                    part_numbers: skus,
                    brand_choices: choices,
                });
                mergeResolvedResults(result, skus);
            } catch (error) {
                console.error(error);
                setStatus('Die Auswahl konnte nicht übernommen werden.');
            }
        }

        async function uploadPartsList() {
            const file = document.getElementById('partsFile').files[0];
            if (!file) {
                setStatus('Bitte zuerst eine Excel- oder CSV-Datei auswählen.');
                return;
            }
            setStatus('Liste wird geprüft...');
            try {
                const formData = new FormData();
                formData.append('file', file);
                const response = await fetch(BAF_API.upload, {
                    method: 'POST',
                    body: formData,
                    credentials: 'same-origin',
                });
                if (!response.ok) throw new Error('HTTP ' + response.status);
                const data = await response.json();
                renderResults(data);
            } catch (error) {
                console.error(error);
                setStatus('Die Liste konnte nicht verarbeitet werden. Bitte Format prüfen.');
            }
        }

        function buildProductRow(product) {
            const row = document.createElement('tr');
            row.dataset.productId = product.id;
            row.dataset.partKey = (product.part_number || '').toUpperCase();
            const isBlocked = product.orderable === false;
            if (isBlocked) {
                row.classList.add('baf-row-blocked');
                row.dataset.blocked = '1';
            }
            const moq = Number(product.moq) > 0 ? Number(product.moq) : 1;
            const selectCell = isBlocked
                ? '<td></td>'
                : '<td><input class="baf-row-select" type="checkbox"/></td>';
            const qtyCell = isBlocked
                ? '<td></td>'
                : '<td><input class="baf-qty" type="number" min="' + moq + '" step="' + moq + '" value="' + moq + '"/></td>';
            const moqCell = '<td><span class="baf-badge">' + escapeHtml(moq) + '</span></td>';
            const surchargeCell = '<td>' + (product.surcharge ? '<span class="baf-surcharge">' + escapeHtml(product.surcharge) + '</span>' : '<span class="text-muted">—</span>') + '</td>';
            let actionCell;
            if (isBlocked && product.replacement_url) {
                actionCell = '<td><a class="baf-add-btn baf-add-btn-link" href="' + escapeHtml(product.replacement_url) + '">Nachfolger ansehen</a></td>';
            } else if (isBlocked) {
                actionCell = '<td><span class="baf-blocked-label">Nicht bestellbar</span></td>';
            } else {
                actionCell = '<td><button class="baf-add-btn" type="button">In den Warenkorb</button></td>';
            }
            row.innerHTML =
                selectCell +
                '<td><span class="baf-part-number">' + escapeHtml(product.part_number) + '</span></td>' +
                '<td><span class="baf-product-name">' + escapeHtml(product.name) + '</span></td>' +
                '<td>' + escapeHtml(product.brand || '—') + '</td>' +
                '<td>' + escapeHtml(product.mod || '—') + '</td>' +
                '<td>' + escapeHtml(product.type || '—') + '</td>' +
                '<td><span class="baf-badge ' + escapeHtml(product.availability_type || '') + '">' + escapeHtml(product.availability || '') + '</span></td>' +
                '<td>' + escapeHtml(product.delivery_time || '') + '</td>' +
                moqCell +
                surchargeCell +
                '<td><strong>' + escapeHtml(product.price || 'Preis nach Login') + '</strong></td>' +
                qtyCell +
                actionCell;
            const selectCb = row.querySelector('.baf-row-select');
            if (selectCb) {
                selectCb.addEventListener('change', updateSelectedButton);
            }
            const addBtn = row.querySelector('button.baf-add-btn');
            if (addBtn) {
                addBtn.addEventListener('click', function () {
                    const qty = Number(row.querySelector('.baf-qty').value || 1);
                    addItemsToCart([{ product_id: product.id, quantity: qty }]);
                });
            }
            return row;
        }

        function renderResults(data) {
            const products = (data && data.products) || [];
            const ambiguous = (data && data.ambiguous) || [];
            const notFound = (data && data.not_found) || [];

            resultsBody.innerHTML = '';
            selectAll.checked = false;

            products.forEach(function (product) {
                resultsBody.appendChild(buildProductRow(product));
            });

            renderAmbiguous(ambiguous);
            renderNotFound(notFound);

            const hasRows = products.length > 0;
            resultsTableWrap.hidden = !hasRows;
            resultsEmpty.hidden = hasRows || ambiguous.length > 0 || notFound.length > 0;

            const parts = [];
            if (products.length) parts.push(products.length + ' Artikel gefunden.');
            if (ambiguous.length) parts.push(ambiguous.length + ' SKU(s) mehrdeutig — bitte Marke wählen.');
            if (notFound.length) parts.push(notFound.length + ' nicht gefunden.');
            setStatus(parts.join(' ') || 'Keine Treffer.');
            updateSelectedButton();
        }

        function mergeResolvedResults(data, resolvedSkus) {
            const products = (data && data.products) || [];
            const notFound = (data && data.not_found) || [];

            // 1. Insert / replace product rows
            products.forEach(function (product) {
                const key = (product.part_number || '').toUpperCase();
                const existing = resultsBody.querySelector('tr[data-part-key="' + key + '"]');
                const newRow = buildProductRow(product);
                newRow.classList.add('is-updated');
                if (existing) {
                    resultsBody.replaceChild(newRow, existing);
                } else {
                    resultsBody.appendChild(newRow);
                }
            });

            // 2. Remove resolved rows from the ambiguous block (only those actually returned)
            const resolvedKeys = new Set(products.map(function (p) { return (p.part_number || '').toUpperCase(); }));
            resolvedSkus.forEach(function (sku) {
                const key = sku.toUpperCase();
                if (!resolvedKeys.has(key)) return;
                const row = ambiguousBox.querySelector('tr.baf-ambiguous-row[data-sku-key="' + key + '"]');
                if (row) row.remove();
            });

            // 3. Hide ambiguous block if empty; show table if it now has rows
            const remaining = ambiguousBox.querySelectorAll('tr.baf-ambiguous-row').length;
            if (!remaining) {
                ambiguousBox.hidden = true;
                ambiguousBox.innerHTML = '';
            } else {
                updateAmbiguousToolbar();
            }

            const hasRows = resultsBody.querySelectorAll('tr').length > 0;
            resultsTableWrap.hidden = !hasRows;
            if (hasRows) resultsEmpty.hidden = true;

            const msgParts = [];
            if (products.length) msgParts.push(products.length + ' Artikel übernommen.');
            if (notFound.length) msgParts.push(notFound.length + ' nicht gefunden.');
            if (remaining) msgParts.push(remaining + ' weiterhin offen.');
            setStatus(msgParts.join(' ') || 'Keine Änderung.');
            updateSelectedButton();
        }

        function renderAmbiguous(ambiguous) {
            if (!ambiguous.length) { ambiguousBox.hidden = true; ambiguousBox.innerHTML = ''; return; }
            let rows = '';
            ambiguous.forEach(function (entry) {
                const opts = entry.matches.map(function (m) {
                    return '<option value="' + escapeHtml(m.brand_id) + '">' + escapeHtml(m.brand) + ' — ' + escapeHtml(m.name) + '</option>';
                }).join('');
                const skuKey = (entry.part_number || '').toUpperCase();
                rows += '<tr class="baf-ambiguous-row" data-sku="' + escapeHtml(entry.part_number) + '" data-sku-key="' + escapeHtml(skuKey) + '">' +
                        '<td><input type="checkbox" class="baf-amb-select"/></td>' +
                        '<td><span class="baf-part-number">' + escapeHtml(entry.part_number) + '</span></td>' +
                        '<td><select class="baf-brand-pick"><option value="">Marke wählen…</option>' + opts + '</select></td>' +
                        '</tr>';
            });
            // Build union of all brand options for the bulk-set dropdown
            const allBrands = new Map();
            ambiguous.forEach(function (entry) {
                entry.matches.forEach(function (m) {
                    if (m.brand_id && !allBrands.has(m.brand_id)) {
                        allBrands.set(m.brand_id, m.brand);
                    }
                });
            });
            let bulkOpts = '<option value="">Marke wählen…</option>';
            allBrands.forEach(function (name, id) {
                bulkOpts += '<option value="' + escapeHtml(id) + '">' + escapeHtml(name) + '</option>';
            });

            ambiguousBox.innerHTML =
                '<h3>Mehrdeutige Teilenummern</h3>' +
                '<p>Diese SKUs existieren bei mehreren Marken. Wählen Sie die Marke je SKU und klicken Sie „Ausgewählte übernehmen".</p>' +
                '<div class="baf-ambiguous-toolbar">' +
                  '<label><input type="checkbox" id="ambSelectAll"/> Alle auswählen</label>' +
                  '<div class="baf-bulk-brand">' +
                    '<span>Marke für ausgewählte:</span>' +
                    '<select id="ambBulkBrand">' + bulkOpts + '</select>' +
                    '<button type="button" class="baf-secondary" id="ambBulkApplyBtn" disabled="disabled">Anwenden</button>' +
                  '</div>' +
                  '<button type="button" id="ambResolveBtn" disabled="disabled">Ausgewählte übernehmen</button>' +
                '</div>' +
                '<table class="baf-table">' +
                  '<thead><tr><th style="width:36px"></th><th>Teilenummer</th><th>Marke</th></tr></thead>' +
                  '<tbody>' + rows + '</tbody>' +
                '</table>';
            ambiguousBox.hidden = false;

            const selAll = ambiguousBox.querySelector('#ambSelectAll');
            const resolveBtn = ambiguousBox.querySelector('#ambResolveBtn');
            const bulkBrandSel = ambiguousBox.querySelector('#ambBulkBrand');
            const bulkApplyBtn = ambiguousBox.querySelector('#ambBulkApplyBtn');

            function refreshBulkApply() {
                const anyChecked = ambiguousBox.querySelectorAll('.baf-amb-select:checked').length > 0;
                bulkApplyBtn.disabled = !(anyChecked && bulkBrandSel.value);
            }
            bulkBrandSel.addEventListener('change', refreshBulkApply);
            bulkApplyBtn.addEventListener('click', function () {
                const brandId = bulkBrandSel.value;
                if (!brandId) return;
                let applied = 0;
                let skipped = 0;
                ambiguousBox.querySelectorAll('tr.baf-ambiguous-row').forEach(function (row) {
                    const cb = row.querySelector('.baf-amb-select');
                    if (!cb.checked) return;
                    const sel = row.querySelector('.baf-brand-pick');
                    const opt = sel.querySelector('option[value="' + brandId + '"]');
                    if (opt) { sel.value = brandId; applied++; }
                    else { skipped++; }
                });
                updateAmbiguousToolbar();
                const msg = applied + ' Zeile(n) auf „' + bulkBrandSel.options[bulkBrandSel.selectedIndex].text + '" gesetzt.' +
                            (skipped ? ' ' + skipped + ' übersprungen (Marke nicht verfügbar).' : '');
                setStatus(msg);
            });

            selAll.addEventListener('change', function () {
                ambiguousBox.querySelectorAll('.baf-amb-select').forEach(function (cb) { cb.checked = selAll.checked; });
                updateAmbiguousToolbar();
                refreshBulkApply();
            });
            ambiguousBox.querySelectorAll('.baf-amb-select').forEach(function (cb) {
                cb.addEventListener('change', function () {
                    updateAmbiguousToolbar();
                    refreshBulkApply();
                });
            });
            ambiguousBox.querySelectorAll('.baf-brand-pick').forEach(function (sel) {
                sel.addEventListener('change', function () {
                    // Auto-tick the row when the user picks a brand
                    const row = sel.closest('tr.baf-ambiguous-row');
                    const cb = row.querySelector('.baf-amb-select');
                    if (sel.value && !cb.checked) cb.checked = true;
                    updateAmbiguousToolbar();
                });
            });
            resolveBtn.addEventListener('click', function () {
                const choices = {};
                ambiguousBox.querySelectorAll('tr.baf-ambiguous-row').forEach(function (row) {
                    const cb = row.querySelector('.baf-amb-select');
                    const brandVal = row.querySelector('.baf-brand-pick').value;
                    if (cb.checked && brandVal) {
                        choices[row.dataset.sku] = Number(brandVal);
                    }
                });
                resolveAmbiguous(choices);
            });

            updateAmbiguousToolbar();
        }

        function updateAmbiguousToolbar() {
            const rows = ambiguousBox.querySelectorAll('tr.baf-ambiguous-row');
            if (!rows.length) return;
            let ready = 0;
            rows.forEach(function (row) {
                const cb = row.querySelector('.baf-amb-select');
                const sel = row.querySelector('.baf-brand-pick');
                if (cb.checked && sel.value) ready++;
            });
            const btn = ambiguousBox.querySelector('#ambResolveBtn');
            const selAll = ambiguousBox.querySelector('#ambSelectAll');
            if (btn) {
                btn.disabled = ready === 0;
                btn.textContent = ready ? ready + ' ausgewählte übernehmen' : 'Ausgewählte übernehmen';
            }
            if (selAll) {
                const checked = ambiguousBox.querySelectorAll('.baf-amb-select:checked').length;
                selAll.checked = checked > 0 && checked === rows.length;
            }
        }

        function renderNotFound(notFound) {
            if (!notFound.length) { notFoundBox.hidden = true; notFoundBox.innerHTML = ''; return; }
            notFoundBox.innerHTML = '<h3>Nicht gefunden</h3><p>' +
                notFound.map(escapeHtml).join(', ') + '</p>';
            notFoundBox.hidden = false;
        }

        function getSelectedItems() {
            return Array.from(document.querySelectorAll('#resultsBody tr'))
                .filter(function (row) { return row.querySelector('.baf-row-select').checked; })
                .map(function (row) {
                    return {
                        product_id: Number(row.dataset.productId),
                        quantity: Number(row.querySelector('.baf-qty').value || 1),
                    };
                });
        }

        async function addItemsToCart(items) {
            setStatus('Artikel werden in den Warenkorb gelegt...');
            try {
                const result = await jsonrpc(BAF_API.addToCart, { items: items });
                if (!result || !result.success) throw new Error('Warenkorb fehlgeschlagen');
                if (result.cart_quantity != null) {
                    cartInfo.textContent = result.cart_quantity + ' Artikel im Warenkorb';
                }
                setStatus(items.length + ' Position(en) wurden dem Warenkorb hinzugefügt.');
            } catch (error) {
                console.error(error);
                setStatus('Artikel konnten nicht hinzugefügt werden. Bitte erneut versuchen.');
            }
        }

        function updateSelectedButton() {
            const count = document.querySelectorAll('.baf-row-select:checked').length;
            addSelectedBtn.disabled = count === 0;
            addSelectedBtn.textContent = count ? count + ' ausgewählte in den Warenkorb' : 'Ausgewählte in den Warenkorb';
        }

        function setStatus(message) { statusBox.textContent = message; }
    });
})();
